// Extract values
const entry = parseFloat($json.entry_price);
const current = parseFloat($json.price);   // IMPORTANT FIX
const quantity = parseFloat($json.quantity);

// Validate values
if (!entry || !current || !quantity) {
  return $json;
}

// Calculate PnL
const pnl = (current - entry) * quantity;

// Fees (0.1%)
const fees = Math.abs(pnl) * 0.001;

// Net PnL
const net_pnl = pnl - fees;

// ROI
const investment = entry * quantity;
const roi = (net_pnl / investment) * 100;

// Attach results
$json.current_price = current;
$json.pnl = pnl;
$json.fees = fees;
$json.net_pnl = net_pnl;
$json.roi = roi.toFixed(2);

return $json;
